# =============================================================================
# database.py - Database Layer with Transaction Support
# =============================================================================

class TransactionError(Exception):
    """Raised when a database transaction fails."""
    pass


class DatabaseBackup:
    """Handles data backup and recovery mechanisms."""

    def __init__(self):
        self._backups = []
        self._max_backups = 10

    def create_backup(self, data: dict) -> str:
        backup_id = str(uuid.uuid4())
        backup = {
            "id": backup_id,
            "timestamp": datetime.utcnow().isoformat(),
            "data": copy.deepcopy(data),
        }
        self._backups.append(backup)
        if len(self._backups) > self._max_backups:
            self._backups.pop(0)
        return backup_id

    def restore_backup(self, backup_id: str) -> Optional[dict]:
        for backup in self._backups:
            if backup["id"] == backup_id:
                return copy.deepcopy(backup["data"])
        return None

    def list_backups(self) -> list:
        return [{"id": b["id"], "timestamp": b["timestamp"]} for b in self._backups]


class Database:
    """In-memory database with transaction support, indexing, and backup/recovery."""

    def __init__(self):
        self._collections: dict[str, dict[str, dict]] = {}
        self._indexes: dict[str, dict[str, dict[str, list]]] = {}
        self._lock = threading.RLock()
        self._transaction_active = False
        self._transaction_log: list[dict] = []
        self._backup_manager = DatabaseBackup()
        self._initialize_collections()

    def _initialize_collections(self):
        collections = [
            "users", "projects", "tasks", "resources",
            "messages", "channels", "reports", "integrations",
            "audit_log", "notifications", "departments",
            "time_entries", "comments", "attachments",
        ]
        for name in collections:
            self._collections[name] = {}
            self._indexes[name] = {}

    def begin_transaction(self):
        self._lock.acquire()
        self._transaction_active = True
        self._transaction_log = []

    def commit_transaction(self):
        self._transaction_active = False
        self._transaction_log = []
        self._lock.release()

    def rollback_transaction(self):
        for entry in reversed(self._transaction_log):
            collection = entry["collection"]
            if entry["operation"] == "insert":
                self._collections[collection].pop(entry["id"], None)
            elif entry["operation"] == "update":
                if entry["previous"] is None:
                    self._collections[collection].pop(entry["id"], None)
                else:
                    self._collections[collection][entry["id"]] = entry["previous"]
            elif entry["operation"] == "delete":
                self._collections[collection][entry["id"]] = entry["previous"]
        self._transaction_active = False
        self._transaction_log = []
        self._lock.release()

    def insert(self, collection: str, record: dict) -> str:
        record_id = record.get("id", str(uuid.uuid4()))
        record["id"] = record_id
        record["created_at"] = datetime.utcnow().isoformat()
        record["updated_at"] = datetime.utcnow().isoformat()
        with self._lock if not self._transaction_active else _NullContext():
            self._collections[collection][record_id] = record
            self._update_indexes(collection, record)
            if self._transaction_active:
                self._transaction_log.append({
                    "operation": "insert",
                    "collection": collection,
                    "id": record_id,
                })
        return record_id

    def update(self, collection: str, record_id: str, updates: dict) -> Optional[dict]:
        with self._lock if not self._transaction_active else _NullContext():
            if record_id not in self._collections[collection]:
                return None
            previous = copy.deepcopy(self._collections[collection][record_id])
            self._collections[collection][record_id].update(updates)
            self._collections[collection][record_id]["updated_at"] = datetime.utcnow().isoformat()
            self._update_indexes(collection, self._collections[collection][record_id])
            if self._transaction_active:
                self._transaction_log.append({
                    "operation": "update",
                    "collection": collection,
                    "id": record_id,
                    "previous": previous,
                })
            return self._collections[collection][record_id]

    def delete(self, collection: str, record_id: str) -> bool:
        with self._lock if not self._transaction_active else _NullContext():
            if record_id not in self._collections[collection]:
                return False
            previous = copy.deepcopy(self._collections[collection][record_id])
            del self._collections[collection][record_id]
            if self._transaction_active:
                self._transaction_log.append({
                    "operation": "delete",
                    "collection": collection,
                    "id": record_id,
                    "previous": previous,
                })
        return True

    def find_by_id(self, collection: str, record_id: str) -> Optional[dict]:
        return copy.deepcopy(self._collections[collection].get(record_id))

    def find(self, collection: str, filters: Optional[dict] = None) -> list[dict]:
        results = []
        for record in self._collections[collection].values():
            if filters is None or self._matches_filters(record, filters):
                results.append(copy.deepcopy(record))
        return results

    def find_paginated(self, collection: str, filters: Optional[dict] = None,
                       page: int = 1, page_size: int = 20,
                       sort_by: str = "created_at", ascending: bool = False) -> dict:
        results = self.find(collection, filters)
        results.sort(key=lambda r: r.get(sort_by, ""), reverse=not ascending)
        total = len(results)
        start = (page - 1) * page_size
        end = start + page_size
        return {
            "data": results[start:end],
            "total": total,
            "page": page,
            "page_size": page_size,
            "total_pages": (total + page_size - 1) // page_size,
        }

    def count(self, collection: str, filters: Optional[dict] = None) -> int:
        if filters is None:
            return len(self._collections[collection])
        return len(self.find(collection, filters))

    def create_backup(self) -> str:
        with self._lock:
            return self._backup_manager.create_backup(self._collections)

    def restore_from_backup(self, backup_id: str) -> bool:
        with self._lock:
            data = self._backup_manager.restore_backup(backup_id)
            if data is None:
                return False
            self._collections = data
            return True

    def _matches_filters(self, record: dict, filters: dict) -> bool:
        for key, value in filters.items():
            if key.endswith("__in"):
                field = key[:-4]
                if record.get(field) not in value:
                    return False
            elif key.endswith("__gte"):
                field = key[:-5]
                if record.get(field, "") < value:
                    return False
            elif key.endswith("__lte"):
                field = key[:-5]
                if record.get(field, "") > value:
                    return False
            elif key.endswith("__contains"):
                field = key[:-10]
                if value.lower() not in str(record.get(field, "")).lower():
                    return False
            elif record.get(key) != value:
                return False
        return True

    def _update_indexes(self, collection: str, record: dict):
        for field, index in self._indexes[collection].items():
            value = record.get(field)
            if value is not None:
                if value not in index:
                    index[value] = []
                if record["id"] not in index[value]:
                    index[value].append(record["id"])

    def create_index(self, collection: str, field: str):
        self._indexes[collection][field] = {}
        for record in self._collections[collection].values():
            value = record.get(field)
            if value is not None:
                if value not in self._indexes[collection][field]:
                    self._indexes[collection][field][value] = []
                self._indexes[collection][field][value].append(record["id"])


class _NullContext:
    """No-op context manager for when lock is already held."""
    def __enter__(self):
        return self
    def __exit__(self, *args):
        pass


