# =============================================================================
# auth.py - Authentication and Role-Based Access Control
# =============================================================================

class AuthenticationError(Exception):
    pass


class AuthorizationError(Exception):
    pass


class AuthService:
    """Handles authentication, sessions, and role-based access control."""

    ROLE_PERMISSIONS = {
        UserRole.ADMIN: {
            "users": ["create", "read", "update", "delete"],
            "projects": ["create", "read", "update", "delete"],
            "tasks": ["create", "read", "update", "delete", "assign"],
            "resources": ["create", "read", "update", "delete", "allocate"],
            "reports": ["create", "read", "export"],
            "integrations": ["create", "read", "update", "delete"],
            "departments": ["create", "read", "update", "delete"],
            "settings": ["read", "update"],
        },
        UserRole.MANAGER: {
            "users": ["read"],
            "projects": ["create", "read", "update"],
            "tasks": ["create", "read", "update", "assign"],
            "resources": ["read", "allocate"],
            "reports": ["create", "read", "export"],
            "integrations": ["read"],
            "departments": ["read"],
            "settings": ["read"],
        },
        UserRole.TEAM_LEAD: {
            "users": ["read"],
            "projects": ["read", "update"],
            "tasks": ["create", "read", "update", "assign"],
            "resources": ["read"],
            "reports": ["read"],
            "integrations": ["read"],
            "departments": ["read"],
            "settings": ["read"],
        },
        UserRole.DEVELOPER: {
            "users": ["read"],
            "projects": ["read"],
            "tasks": ["read", "update"],
            "resources": ["read"],
            "reports": ["read"],
            "integrations": ["read"],
            "departments": ["read"],
            "settings": ["read"],
        },
        UserRole.VIEWER: {
            "users": ["read"],
            "projects": ["read"],
            "tasks": ["read"],
            "resources": ["read"],
            "reports": ["read"],
            "integrations": [],
            "departments": ["read"],
            "settings": [],
        },
    }

    def __init__(self, db: Database):
        self._db = db
        self._sessions: dict[str, dict] = {}

    def register_user(self, username: str, password: str, email: str,
                      role: UserRole, department_id: str = "",
                      full_name: str = "") -> dict:
        existing = self._db.find("users", {"username": username})
        if existing:
            raise AuthenticationError("Username already exists")
        password_hash = self._hash_password(password)
        user = {
            "username": username,
            "password_hash": password_hash,
            "email": email,
            "role": role.value,
            "department_id": department_id,
            "full_name": full_name or username,
            "is_active": True,
            "last_login": None,
            "preferences": {},
        }
        user_id = self._db.insert("users", user)
        return self._sanitize_user(self._db.find_by_id("users", user_id))

    def authenticate(self, username: str, password: str) -> dict:
        users = self._db.find("users", {"username": username})
        if not users:
            raise AuthenticationError("Invalid credentials")
        user = users[0]
        if not user.get("is_active", True):
            raise AuthenticationError("Account is deactivated")
        if user["password_hash"] != self._hash_password(password):
            raise AuthenticationError("Invalid credentials")
        session_token = str(uuid.uuid4())
        self._sessions[session_token] = {
            "user_id": user["id"],
            "role": user["role"],
            "created_at": datetime.utcnow().isoformat(),
            "expires_at": (datetime.utcnow() + timedelta(hours=8)).isoformat(),
        }
        self._db.update("users", user["id"], {"last_login": datetime.utcnow().isoformat()})
        return {"token": session_token, "user": self._sanitize_user(user)}

    def validate_session(self, token: str) -> dict:
        session = self._sessions.get(token)
        if not session:
            raise AuthenticationError("Invalid session")
        if datetime.fromisoformat(session["expires_at"]) < datetime.utcnow():
            del self._sessions[token]
            raise AuthenticationError("Session expired")
        return session

    def authorize(self, token: str, resource: str, action: str) -> bool:
        session = self.validate_session(token)
        role = UserRole(session["role"])
        permissions = self.ROLE_PERMISSIONS.get(role, {})
        allowed_actions = permissions.get(resource, [])
        if action not in allowed_actions:
            raise AuthorizationError(
                f"Role '{role.value}' cannot '{action}' on '{resource}'"
            )
        return True

    def logout(self, token: str):
        self._sessions.pop(token, None)

    def get_current_user(self, token: str) -> dict:
        session = self.validate_session(token)
        user = self._db.find_by_id("users", session["user_id"])
        return self._sanitize_user(user)

    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()

    def _sanitize_user(self, user: dict) -> dict:
        if user is None:
            return {}
        sanitized = {k: v for k, v in user.items() if k != "password_hash"}
        return sanitized


def require_auth(resource: str, action: str):
    """Decorator for role-based access control on API endpoints."""
    def decorator(func):
        @wraps(func)
        def wrapper(self, token: str, *args, **kwargs):
            self.auth_service.authorize(token, resource, action)
            return func(self, token, *args, **kwargs)
        return wrapper
    return decorator


