class TaskManagementService:
    """Handles task creation, assignment, tracking, and workflow management."""

    def __init__(self, db: Database, auth_service: AuthService):
        self._db = db
        self.auth_service = auth_service

    @require_auth("tasks", "create")
    def create_task(self, token: str, project_id: str, title: str,
                    description: str = "", priority: TaskPriority = TaskPriority.MEDIUM,
                    assignee_id: str = "", due_date: str = "",
                    tags: list[str] = None, estimated_hours: float = 0,
                    parent_task_id: str = "") -> dict:
        session = self.auth_service.validate_session(token)
        task = {
            "project_id": project_id,
            "title": title,
            "description": description,
            "status": TaskStatus.TODO.value,
            "priority": priority.value,
            "assignee_id": assignee_id,
            "reporter_id": session["user_id"],
            "due_date": due_date,
            "tags": tags or [],
            "estimated_hours": estimated_hours,
            "actual_hours": 0,
            "parent_task_id": parent_task_id,
            "subtask_ids": [],
            "dependencies": [],
            "comments": [],
            "attachments": [],
            "history": [{"action": "created", "timestamp": datetime.utcnow().isoformat(),
                         "user_id": session["user_id"]}],
        }
        task_id = self._db.insert("tasks", task)
        if parent_task_id:
            parent = self._db.find_by_id("tasks", parent_task_id)
            if parent:
                subtasks = parent.get("subtask_ids", [])
                subtasks.append(task_id)
                self._db.update("tasks", parent_task_id, {"subtask_ids": subtasks})
        self._log_audit("task_created", session["user_id"], {"task_id": task_id, "title": title})
        return self._db.find_by_id("tasks", task_id)

    @require_auth("tasks", "update")
    def update_task_status(self, token: str, task_id: str, new_status: TaskStatus) -> dict:
        session = self.auth_service.validate_session(token)
        task = self._db.find_by_id("tasks", task_id)
        if not task:
            raise ValueError("Task not found")
        valid_transitions = {
            TaskStatus.BACKLOG: [TaskStatus.TODO],
            TaskStatus.TODO: [TaskStatus.IN_PROGRESS, TaskStatus.BLOCKED],
            TaskStatus.IN_PROGRESS: [TaskStatus.IN_REVIEW, TaskStatus.BLOCKED, TaskStatus.TODO],
            TaskStatus.IN_REVIEW: [TaskStatus.DONE, TaskStatus.IN_PROGRESS],
            TaskStatus.BLOCKED: [TaskStatus.TODO, TaskStatus.IN_PROGRESS],
            TaskStatus.DONE: [TaskStatus.TODO],
        }
        current = TaskStatus(task["status"])
        if new_status not in valid_transitions.get(current, []):
            raise ValueError(f"Invalid transition from {current.value} to {new_status.value}")
        history = task.get("history", [])
        history.append({
            "action": "status_changed",
            "from": current.value,
            "to": new_status.value,
            "timestamp": datetime.utcnow().isoformat(),
            "user_id": session["user_id"],
        })
        updates = {"status": new_status.value, "history": history}
        if new_status == TaskStatus.DONE:
            updates["completed_at"] = datetime.utcnow().isoformat()
        return self._db.update("tasks", task_id, updates)

    @require_auth("tasks", "assign")
    def assign_task(self, token: str, task_id: str, assignee_id: str) -> dict:
        session = self.auth_service.validate_session(token)
        task = self._db.find_by_id("tasks", task_id)
        if not task:
            raise ValueError("Task not found")
        user = self._db.find_by_id("users", assignee_id)
        if not user:
            raise ValueError("Assignee not found")
        history = task.get("history", [])
        history.append({
            "action": "assigned",
            "assignee_id": assignee_id,
            "timestamp": datetime.utcnow().isoformat(),
            "user_id": session["user_id"],
        })
        return self._db.update("tasks", task_id, {"assignee_id": assignee_id, "history": history})

    @require_auth("tasks", "read")
    def get_task(self, token: str, task_id: str) -> Optional[dict]:
        return self._db.find_by_id("tasks", task_id)

    @require_auth("tasks", "read")
    def list_tasks(self, token: str, project_id: str = "",
                   status: str = "", assignee_id: str = "",
                   priority: str = "", page: int = 1,
                   page_size: int = 20) -> dict:
        filters = {}
        if project_id:
            filters["project_id"] = project_id
        if status:
            filters["status"] = status
        if assignee_id:
            filters["assignee_id"] = assignee_id
        if priority:
            filters["priority"] = priority
        return self._db.find_paginated("tasks", filters, page, page_size)

    @require_auth("tasks", "update")
    def add_comment(self, token: str, task_id: str, content: str) -> dict:
        session = self.auth_service.validate_session(token)
        task = self._db.find_by_id("tasks", task_id)
        if not task:
            raise ValueError("Task not found")
        comment = {
            "id": str(uuid.uuid4()),
            "user_id": session["user_id"],
            "content": content,
            "timestamp": datetime.utcnow().isoformat(),
        }
        comments = task.get("comments", [])
        comments.append(comment)
        self._db.update("tasks", task_id, {"comments": comments})
        return comment

    @require_auth("tasks", "update")
    def log_time(self, token: str, task_id: str, hours: float, description: str = "") -> dict:
        session = self.auth_service.validate_session(token)
        task = self._db.find_by_id("tasks", task_id)
        if not task:
            raise ValueError("Task not found")
        time_entry = {
            "task_id": task_id,
            "user_id": session["user_id"],
            "hours": hours,
            "description": description,
            "date": datetime.utcnow().date().isoformat(),
        }
        entry_id = self._db.insert("time_entries", time_entry)
        actual = task.get("actual_hours", 0) + hours
        self._db.update("tasks", task_id, {"actual_hours": actual})
        return self._db.find_by_id("time_entries", entry_id)

    def _log_audit(self, action: str, user_id: str, details: dict):
        self._db.insert("audit_log", {
            "action": action,
            "user_id": user_id,
            "details": details,
            "timestamp": datetime.utcnow().isoformat(),
        })


