class ProjectManagementService:
    """Manages projects, milestones, and project lifecycle."""

    def __init__(self, db: Database, auth_service: AuthService):
        self._db = db
        self.auth_service = auth_service

    @require_auth("projects", "create")
    def create_project(self, token: str, name: str, description: str = "",
                       department_id: str = "", start_date: str = "",
                       end_date: str = "", budget: float = 0,
                       team_members: list[str] = None) -> dict:
        session = self.auth_service.validate_session(token)
        project = {
            "name": name,
            "description": description,
            "status": ProjectStatus.PLANNING.value,
            "department_id": department_id,
            "owner_id": session["user_id"],
            "start_date": start_date or datetime.utcnow().date().isoformat(),
            "end_date": end_date,
            "budget": budget,
            "spent_budget": 0,
            "team_members": team_members or [],
            "milestones": [],
            "tags": [],
            "settings": {"notifications_enabled": True, "auto_assign": False},
        }
        project_id = self._db.insert("projects", project)
        return self._db.find_by_id("projects", project_id)

    @require_auth("projects", "update")
    def update_project(self, token: str, project_id: str, updates: dict) -> dict:
        allowed_fields = {
            "name", "description", "status", "end_date", "budget",
            "team_members", "tags", "settings",
        }
        filtered_updates = {k: v for k, v in updates.items() if k in allowed_fields}
        result = self._db.update("projects", project_id, filtered_updates)
        if result is None:
            raise ValueError("Project not found")
        return result

    @require_auth("projects", "read")
    def get_project(self, token: str, project_id: str) -> Optional[dict]:
        return self._db.find_by_id("projects", project_id)

    @require_auth("projects", "read")
    def list_projects(self, token: str, status: str = "",
                      department_id: str = "", page: int = 1,
                      page_size: int = 20) -> dict:
        filters = {}
        if status:
            filters["status"] = status
        if department_id:
            filters["department_id"] = department_id
        return self._db.find_paginated("projects", filters, page, page_size)

    @require_auth("projects", "update")
    def add_milestone(self, token: str, project_id: str,
                      title: str, due_date: str, description: str = "") -> dict:
        project = self._db.find_by_id("projects", project_id)
        if not project:
            raise ValueError("Project not found")
        milestone = {
            "id": str(uuid.uuid4()),
            "title": title,
            "description": description,
            "due_date": due_date,
            "status": "pending",
            "created_at": datetime.utcnow().isoformat(),
        }
        milestones = project.get("milestones", [])
        milestones.append(milestone)
        self._db.update("projects", project_id, {"milestones": milestones})
        return milestone

    @require_auth("projects", "read")
    def get_project_stats(self, token: str, project_id: str) -> dict:
        tasks = self._db.find("tasks", {"project_id": project_id})
        total = len(tasks)
        if total == 0:
            return {"total_tasks": 0, "completion_rate": 0, "status_breakdown": {}}
        done = sum(1 for t in tasks if t["status"] == TaskStatus.DONE.value)
        status_breakdown = defaultdict(int)
        priority_breakdown = defaultdict(int)
        for task in tasks:
            status_breakdown[task["status"]] += 1
            priority_breakdown[task.get("priority", "medium")] += 1
        total_estimated = sum(t.get("estimated_hours", 0) for t in tasks)
        total_actual = sum(t.get("actual_hours", 0) for t in tasks)
        overdue = sum(1 for t in tasks
                      if t.get("due_date") and t["due_date"] < datetime.utcnow().isoformat()
                      and t["status"] != TaskStatus.DONE.value)
        return {
            "total_tasks": total,
            "completed_tasks": done,
            "completion_rate": round(done / total * 100, 1),
            "status_breakdown": dict(status_breakdown),
            "priority_breakdown": dict(priority_breakdown),
            "total_estimated_hours": total_estimated,
            "total_actual_hours": total_actual,
            "overdue_tasks": overdue,
        }


