class ResourceAllocationService:
    """Manages resource allocation, scheduling, and utilization tracking."""

    def __init__(self, db: Database, auth_service: AuthService):
        self._db = db
        self.auth_service = auth_service

    @require_auth("resources", "create")
    def create_resource(self, token: str, name: str,
                        resource_type: ResourceType, capacity: float = 1.0,
                        cost_per_hour: float = 0, department_id: str = "",
                        skills: list[str] = None) -> dict:
        resource = {
            "name": name,
            "type": resource_type.value,
            "capacity": capacity,
            "available_capacity": capacity,
            "cost_per_hour": cost_per_hour,
            "department_id": department_id,
            "skills": skills or [],
            "allocations": [],
            "is_active": True,
        }
        resource_id = self._db.insert("resources", resource)
        return self._db.find_by_id("resources", resource_id)

    @require_auth("resources", "allocate")
    def allocate_resource(self, token: str, resource_id: str,
                          project_id: str, allocation_percentage: float,
                          start_date: str, end_date: str,
                          role: str = "") -> dict:
        resource = self._db.find_by_id("resources", resource_id)
        if not resource:
            raise ValueError("Resource not found")
        if allocation_percentage > resource.get("available_capacity", 0) * 100:
            raise ValueError("Insufficient resource capacity")
        allocation = {
            "id": str(uuid.uuid4()),
            "project_id": project_id,
            "percentage": allocation_percentage,
            "start_date": start_date,
            "end_date": end_date,
            "role": role,
            "status": "active",
        }
        allocations = resource.get("allocations", [])
        allocations.append(allocation)
        new_available = resource["available_capacity"] - (allocation_percentage / 100)
        self._db.update("resources", resource_id, {
            "allocations": allocations,
            "available_capacity": max(0, new_available),
        })
        return allocation

    @require_auth("resources", "read")
    def get_resource_utilization(self, token: str, resource_id: str) -> dict:
        resource = self._db.find_by_id("resources", resource_id)
        if not resource:
            raise ValueError("Resource not found")
        total_capacity = resource.get("capacity", 1.0)
        available = resource.get("available_capacity", total_capacity)
        utilized = total_capacity - available
        return {
            "resource_id": resource_id,
            "resource_name": resource.get("name", ""),
            "total_capacity": total_capacity,
            "utilized_capacity": utilized,
            "available_capacity": available,
            "utilization_rate": round(utilized / total_capacity * 100, 1) if total_capacity > 0 else 0,
            "active_allocations": len([a for a in resource.get("allocations", [])
                                       if a.get("status") == "active"]),
        }

    @require_auth("resources", "read")
    def list_resources(self, token: str, resource_type: str = "",
                       department_id: str = "", page: int = 1,
                       page_size: int = 20) -> dict:
        filters = {}
        if resource_type:
            filters["type"] = resource_type
        if department_id:
            filters["department_id"] = department_id
        return self._db.find_paginated("resources", filters, page, page_size)

    @require_auth("resources", "allocate")
    def deallocate_resource(self, token: str, resource_id: str,
                            allocation_id: str) -> dict:
        resource = self._db.find_by_id("resources", resource_id)
        if not resource:
            raise ValueError("Resource not found")
        allocations = resource.get("allocations", [])
        target = None
        for alloc in allocations:
            if alloc["id"] == allocation_id:
                target = alloc
                alloc["status"] = "released"
                break
        if not target:
            raise ValueError("Allocation not found")
        new_available = resource["available_capacity"] + (target["percentage"] / 100)
        self._db.update("resources", resource_id, {
            "allocations": allocations,
            "available_capacity": min(resource["capacity"], new_available),
        })
        return resource


