class CommunicationService:
    """Manages channels, messaging, and real-time communication features."""

    def __init__(self, db: Database, auth_service: AuthService):
        self._db = db
        self.auth_service = auth_service
        self._subscribers: dict[str, list] = {}
        self._online_users: set[str] = set()

    def create_channel(self, token: str, name: str, channel_type: str = "public",
                       members: list[str] = None, project_id: str = "") -> dict:
        session = self.auth_service.validate_session(token)
        channel = {
            "name": name,
            "type": channel_type,
            "members": members or [session["user_id"]],
            "project_id": project_id,
            "creator_id": session["user_id"],
            "is_active": True,
            "pinned_messages": [],
        }
        channel_id = self._db.insert("channels", channel)
        return self._db.find_by_id("channels", channel_id)

    def send_message(self, token: str, channel_id: str, content: str,
                     message_type: str = "text", attachments: list = None) -> dict:
        session = self.auth_service.validate_session(token)
        channel = self._db.find_by_id("channels", channel_id)
        if not channel:
            raise ValueError("Channel not found")
        if session["user_id"] not in channel.get("members", []):
            raise AuthorizationError("Not a member of this channel")
        message = {
            "channel_id": channel_id,
            "sender_id": session["user_id"],
            "content": content,
            "type": message_type,
            "attachments": attachments or [],
            "reactions": {},
            "is_edited": False,
            "read_by": [session["user_id"]],
            "thread_id": "",
        }
        message_id = self._db.insert("messages", message)
        self._notify_channel_members(channel_id, message_id, session["user_id"])
        return self._db.find_by_id("messages", message_id)

    def get_channel_messages(self, token: str, channel_id: str,
                             page: int = 1, page_size: int = 50) -> dict:
        session = self.auth_service.validate_session(token)
        channel = self._db.find_by_id("channels", channel_id)
        if not channel:
            raise ValueError("Channel not found")
        if session["user_id"] not in channel.get("members", []):
            raise AuthorizationError("Not a member of this channel")
        return self._db.find_paginated("messages", {"channel_id": channel_id},
                                       page, page_size, sort_by="created_at", ascending=True)

    def join_channel(self, token: str, channel_id: str) -> dict:
        session = self.auth_service.validate_session(token)
        channel = self._db.find_by_id("channels", channel_id)
        if not channel:
            raise ValueError("Channel not found")
        if channel["type"] == "private":
            raise AuthorizationError("Cannot join private channel without invitation")
        members = channel.get("members", [])
        if session["user_id"] not in members:
            members.append(session["user_id"])
            self._db.update("channels", channel_id, {"members": members})
        return self._db.find_by_id("channels", channel_id)

    def create_direct_message(self, token: str, recipient_id: str, content: str) -> dict:
        session = self.auth_service.validate_session(token)
        sender_id = session["user_id"]
        channels = self._db.find("channels", {"type": "direct"})
        dm_channel = None
        for ch in channels:
            members = set(ch.get("members", []))
            if members == {sender_id, recipient_id}:
                dm_channel = ch
                break
        if not dm_channel:
            dm_channel = {
                "name": f"dm_{sender_id}_{recipient_id}",
                "type": "direct",
                "members": [sender_id, recipient_id],
                "project_id": "",
                "creator_id": sender_id,
                "is_active": True,
                "pinned_messages": [],
            }
            channel_id = self._db.insert("channels", dm_channel)
            dm_channel = self._db.find_by_id("channels", channel_id)
        message = {
            "channel_id": dm_channel["id"],
            "sender_id": sender_id,
            "content": content,
            "type": "text",
            "attachments": [],
            "reactions": {},
            "is_edited": False,
            "read_by": [sender_id],
            "thread_id": "",
        }
        self._db.insert("messages", message)
        return dm_channel

    def set_user_online(self, user_id: str):
        self._online_users.add(user_id)

    def set_user_offline(self, user_id: str):
        self._online_users.discard(user_id)

    def get_online_users(self) -> list[str]:
        return list(self._online_users)

    def subscribe(self, channel_id: str, callback):
        if channel_id not in self._subscribers:
            self._subscribers[channel_id] = []
        self._subscribers[channel_id].append(callback)

    def _notify_channel_members(self, channel_id: str, message_id: str, sender_id: str):
        channel = self._db.find_by_id("channels", channel_id)
        if not channel:
            return
        for member_id in channel.get("members", []):
            if member_id != sender_id:
                self._db.insert("notifications", {
                    "user_id": member_id,
                    "type": "new_message",
                    "channel_id": channel_id,
                    "message_id": message_id,
                    "is_read": False,
                })
        for callback in self._subscribers.get(channel_id, []):
            try:
                callback({"channel_id": channel_id, "message_id": message_id})
            except Exception:
                pass


