class IntegrationAdapter:
    """Base class for third-party integration adapters."""

    def __init__(self, config: dict):
        self.config = config
        self.is_connected = False

    def connect(self) -> bool:
        self.is_connected = True
        return True

    def disconnect(self):
        self.is_connected = False

    def sync(self) -> dict:
        raise NotImplementedError


class CalendarIntegration(IntegrationAdapter):
    """Integration with calendar applications (Google Calendar, Outlook, etc.)."""

    def sync(self) -> dict:
        return {"synced_events": 0, "status": "success", "provider": self.config.get("provider", "generic")}

    def create_event(self, title: str, start: str, end: str, attendees: list[str] = None) -> dict:
        return {
            "id": str(uuid.uuid4()),
            "title": title,
            "start": start,
            "end": end,
            "attendees": attendees or [],
            "status": "created",
            "provider": self.config.get("provider", "generic"),
        }

    def get_availability(self, user_id: str, date: str) -> dict:
        return {"user_id": user_id, "date": date, "available_slots": [
            {"start": "09:00", "end": "12:00"},
            {"start": "13:00", "end": "17:00"},
        ]}


class EmailIntegration(IntegrationAdapter):
    """Integration with email services (SMTP, SendGrid, etc.)."""

    def __init__(self, config: dict):
        super().__init__(config)
        self._sent_emails: list[dict] = []

    def sync(self) -> dict:
        return {"synced_emails": 0, "status": "success", "provider": self.config.get("provider", "smtp")}

    def send_email(self, to: list[str], subject: str, body: str,
                   cc: list[str] = None, attachments: list = None) -> dict:
        email = {
            "id": str(uuid.uuid4()),
            "to": to,
            "cc": cc or [],
            "subject": subject,
            "body": body,
            "attachments": attachments or [],
            "sent_at": datetime.utcnow().isoformat(),
            "status": "sent",
        }
        self._sent_emails.append(email)
        return email

    def send_notification_email(self, to: str, notification_type: str, data: dict) -> dict:
        templates = {
            "task_assigned": "You have been assigned to task: {title}",
            "task_completed": "Task completed: {title}",
            "project_update": "Project update: {project_name}",
            "deadline_reminder": "Reminder: {title} is due on {due_date}",
        }
        subject = templates.get(notification_type, "TeamSyncPro Notification")
        body = subject.format(**data) if data else subject
        return self.send_email([to], f"[TeamSyncPro] {subject}", body)


class CRMIntegration(IntegrationAdapter):
