            "id": str(uuid.uuid4()),
            "name": name,
            "value": value,
            "stage": stage,
            "contact_id": contact_id,
            "created_at": datetime.utcnow().isoformat(),
        }


class IntegrationService:
    """Manages all third-party integrations."""

    ADAPTER_MAP = {
        IntegrationType.CALENDAR: CalendarIntegration,
        IntegrationType.EMAIL: EmailIntegration,
        IntegrationType.CRM: CRMIntegration,
    }

    def __init__(self, db: Database, auth_service: AuthService):
        self._db = db
        self.auth_service = auth_service
        self._active_integrations: dict[str, IntegrationAdapter] = {}

    @require_auth("integrations", "create")
    def register_integration(self, token: str, name: str,
                             integration_type: IntegrationType,
                             config: dict) -> dict:
        integration = {
            "name": name,
            "type": integration_type.value,
            "config": config,
            "status": "registered",
            "last_sync": None,
        }
        integration_id = self._db.insert("integrations", integration)
        adapter_class = self.ADAPTER_MAP.get(integration_type)
        if adapter_class:
            adapter = adapter_class(config)
            self._active_integrations[integration_id] = adapter
        return self._db.find_by_id("integrations", integration_id)

    def connect_integration(self, token: str, integration_id: str) -> dict:
        self.auth_service.validate_session(token)
        adapter = self._active_integrations.get(integration_id)
        if not adapter:
            raise ValueError("Integration not found or not initialized")
        adapter.connect()
        self._db.update("integrations", integration_id, {"status": "connected"})
        return {"status": "connected", "integration_id": integration_id}

    def sync_integration(self, token: str, integration_id: str) -> dict:
        self.auth_service.validate_session(token)
        adapter = self._active_integrations.get(integration_id)
        if not adapter or not adapter.is_connected:
            raise ValueError("Integration not connected")
        result = adapter.sync()
        self._db.update("integrations", integration_id, {
            "last_sync": datetime.utcnow().isoformat(),
            "status": "synced",
        })
        return result

    def get_adapter(self, integration_id: str) -> Optional[IntegrationAdapter]:
        return self._active_integrations.get(integration_id)

    @require_auth("integrations", "read")
    def list_integrations(self, token: str) -> list[dict]:
        return self._db.find("integrations")


