class ReportingService:
    """Generates various reports for project tracking and decision-making."""

    def __init__(self, db: Database, auth_service: AuthService):
        self._db = db
        self.auth_service = auth_service

    @require_auth("reports", "read")
    def generate_project_progress_report(self, token: str, project_id: str) -> dict:
        project = self._db.find_by_id("projects", project_id)
        if not project:
            raise ValueError("Project not found")
        tasks = self._db.find("tasks", {"project_id": project_id})
        total = len(tasks)
        completed = sum(1 for t in tasks if t["status"] == TaskStatus.DONE.value)
        in_progress = sum(1 for t in tasks if t["status"] == TaskStatus.IN_PROGRESS.value)
        blocked = sum(1 for t in tasks if t["status"] == TaskStatus.BLOCKED.value)
        overdue = [t for t in tasks if t.get("due_date")
                   and t["due_date"] < datetime.utcnow().isoformat()
                   and t["status"] != TaskStatus.DONE.value]
        milestones = project.get("milestones", [])
        completed_milestones = sum(1 for m in milestones if m.get("status") == "completed")
        report = {
            "report_type": "project_progress",
            "project_id": project_id,
            "project_name": project.get("name", ""),
            "generated_at": datetime.utcnow().isoformat(),
            "summary": {
                "total_tasks": total,
                "completed": completed,
                "in_progress": in_progress,
                "blocked": blocked,
                "completion_percentage": round(completed / total * 100, 1) if total > 0 else 0,
            },
            "milestones": {
                "total": len(milestones),
                "completed": completed_milestones,
            },
            "overdue_tasks": [{"id": t["id"], "title": t["title"], "due_date": t["due_date"]}
                             for t in overdue],
            "budget": {
                "allocated": project.get("budget", 0),
                "spent": project.get("spent_budget", 0),
                "remaining": project.get("budget", 0) - project.get("spent_budget", 0),
            },
            "timeline": {
                "start_date": project.get("start_date", ""),
                "end_date": project.get("end_date", ""),
                "status": project.get("status", ""),
            },
        }
        self._save_report(token, report)
        return report

    @require_auth("reports", "read")
    def generate_resource_utilization_report(self, token: str,
                                              department_id: str = "") -> dict:
        filters = {}
        if department_id:
            filters["department_id"] = department_id
        resources = self._db.find("resources", filters)
        utilization_data = []
        total_capacity = 0
        total_utilized = 0
        for resource in resources:
            capacity = resource.get("capacity", 1.0)
            available = resource.get("available_capacity", capacity)
            utilized = capacity - available
            total_capacity += capacity
            total_utilized += utilized
            utilization_data.append({
                "resource_id": resource["id"],
                "name": resource.get("name", ""),
                "type": resource.get("type", ""),
                "capacity": capacity,
                "utilized": utilized,
                "utilization_rate": round(utilized / capacity * 100, 1) if capacity > 0 else 0,
                "active_allocations": len([a for a in resource.get("allocations", [])
                                           if a.get("status") == "active"]),
            })
        report = {
            "report_type": "resource_utilization",
            "generated_at": datetime.utcnow().isoformat(),
            "department_id": department_id,
            "summary": {
                "total_resources": len(resources),
                "total_capacity": total_capacity,
                "total_utilized": total_utilized,
                "overall_utilization_rate": round(total_utilized / total_capacity * 100, 1)
                if total_capacity > 0 else 0,
            },
            "resources": utilization_data,
            "recommendations": self._generate_utilization_recommendations(utilization_data),
        }
        self._save_report(token, report)
        return report

    @require_auth("reports", "read")
    def generate_performance_metrics_report(self, token: str,
                                             project_id: str = "",
                                             period_days: int = 30) -> dict:
        cutoff = (datetime.utcnow() - timedelta(days=period_days)).isoformat()
        task_filters = {}
        if project_id:
            task_filters["project_id"] = project_id
        all_tasks = self._db.find("tasks", task_filters)
        completed_in_period = [t for t in all_tasks
                               if t.get("completed_at", "") >= cutoff
                               and t["status"] == TaskStatus.DONE.value]
        time_entries = self._db.find("time_entries")
        recent_entries = [e for e in time_entries if e.get("created_at", "") >= cutoff]
        user_performance = defaultdict(lambda: {
            "tasks_completed": 0, "total_hours": 0, "avg_completion_time": 0,
        })
        for task in completed_in_period:
            assignee = task.get("assignee_id", "")
            if assignee:
                user_performance[assignee]["tasks_completed"] += 1
        for entry in recent_entries:
            user_id = entry.get("user_id", "")
            if user_id:
                user_performance[user_id]["total_hours"] += entry.get("hours", 0)
        velocity = len(completed_in_period)
        avg_cycle_time = 0
        if completed_in_period:
            cycle_times = []
            for task in completed_in_period:
                created = task.get("created_at", "")
                completed = task.get("completed_at", "")
                if created and completed:
                    try:
                        c = datetime.fromisoformat(created)
                        d = datetime.fromisoformat(completed)
                        cycle_times.append((d - c).total_seconds() / 3600)
                    except (ValueError, TypeError):
                        pass
            if cycle_times:
                avg_cycle_time = round(sum(cycle_times) / len(cycle_times), 1)

        report = {
            "report_type": "performance_metrics",
            "generated_at": datetime.utcnow().isoformat(),
            "period_days": period_days,
            "project_id": project_id,
            "summary": {
                "tasks_completed": len(completed_in_period),
                "velocity": velocity,
                "avg_cycle_time_hours": avg_cycle_time,
                "total_hours_logged": sum(e.get("hours", 0) for e in recent_entries),
            },
            "team_performance": dict(user_performance),
            "trends": {
                "completion_trend": "stable",
                "velocity_trend": "improving" if velocity > 5 else "stable",
            },
        }
        self._save_report(token, report)
        return report

    @require_auth("reports", "read")
    def generate_department_summary_report(self, token: str, department_id: str) -> dict:
        projects = self._db.find("projects", {"department_id": department_id})
        resources = self._db.find("resources", {"department_id": department_id})
        users = self._db.find("users", {"department_id": department_id})
        all_tasks = []
        for project in projects:
            tasks = self._db.find("tasks", {"project_id": project["id"]})
            all_tasks.extend(tasks)
        total_tasks = len(all_tasks)
        done = sum(1 for t in all_tasks if t["status"] == TaskStatus.DONE.value)
        report = {
            "report_type": "department_summary",
            "generated_at": datetime.utcnow().isoformat(),
            "department_id": department_id,
            "summary": {
                "total_projects": len(projects),
                "active_projects": sum(1 for p in projects
                                       if p["status"] == ProjectStatus.ACTIVE.value),
                "total_resources": len(resources),
                "team_size": len(users),
                "total_tasks": total_tasks,
                "completed_tasks": done,
                "completion_rate": round(done / total_tasks * 100, 1) if total_tasks > 0 else 0,
            },
            "projects": [{"id": p["id"], "name": p["name"], "status": p["status"]}
                        for p in projects],
        }
        self._save_report(token, report)
        return report

    @require_auth("reports", "export")
    def export_report(self, token: str, report_id: str, format_type: str = "json") -> dict:
        report = self._db.find_by_id("reports", report_id)
        if not report:
            raise ValueError("Report not found")
        if format_type == "json":
            return {"format": "json", "data": json.dumps(report, indent=2)}
        elif format_type == "csv":
            return {"format": "csv", "data": self._to_csv(report)}
        return {"format": format_type, "data": str(report)}

    def _save_report(self, token: str, report: dict) -> str:
        session = self.auth_service.validate_session(token)
        report["generated_by"] = session["user_id"]
        return self._db.insert("reports", report)

    def _generate_utilization_recommendations(self, utilization_data: list) -> list[str]:
        recommendations = []
        for resource in utilization_data:
            rate = resource.get("utilization_rate", 0)
            name = resource.get("name", "Unknown")
            if rate > 90:
                recommendations.append(f"{name} is over-utilized ({rate}%). Consider load balancing.")
            elif rate < 30:
                recommendations.append(f"{name} is under-utilized ({rate}%). Consider reallocation.")
        return recommendations

    def _to_csv(self, report: dict) -> str:
        lines = []
        for key, value in report.items():
            if isinstance(value, dict):
                for k, v in value.items():
                    lines.append(f"{key}.{k},{v}")
            else:
                lines.append(f"{key},{value}")
        return "\n".join(lines)


