            "is_read": False,
        }
        notif_id = self._db.insert("notifications", notification)
        self._dispatch(notification_type, notification)
        return self._db.find_by_id("notifications", notif_id)

    def get_user_notifications(self, user_id: str, unread_only: bool = False,
                               page: int = 1, page_size: int = 20) -> dict:
        filters = {"user_id": user_id}
        if unread_only:
            filters["is_read"] = False
        return self._db.find_paginated("notifications", filters, page, page_size)

    def mark_as_read(self, notification_id: str) -> bool:
        result = self._db.update("notifications", notification_id, {"is_read": True})
        return result is not None

    def mark_all_read(self, user_id: str) -> int:
        notifications = self._db.find("notifications", {"user_id": user_id, "is_read": False})
        count = 0
        for notif in notifications:
            self._db.update("notifications", notif["id"], {"is_read": True})
            count += 1
        return count

    def register_handler(self, notification_type: str, handler):
        if notification_type not in self._handlers:
            self._handlers[notification_type] = []
        self._handlers[notification_type].append(handler)

    def _dispatch(self, notification_type: str, notification: dict):
        for handler in self._handlers.get(notification_type, []):
            try:
                handler(notification)
            except Exception:
                pass


