class DepartmentService:
    """Manages organizational departments."""

    def __init__(self, db: Database, auth_service: AuthService):
        self._db = db
        self.auth_service = auth_service

    @require_auth("departments", "create")
    def create_department(self, token: str, name: str, head_id: str = "",
                          description: str = "", parent_id: str = "") -> dict:
        department = {
            "name": name,
            "head_id": head_id,
            "description": description,
            "parent_id": parent_id,
            "is_active": True,
        }
        dept_id = self._db.insert("departments", department)
        return self._db.find_by_id("departments", dept_id)

    @require_auth("departments", "read")
    def get_department(self, token: str, department_id: str) -> Optional[dict]:
        return self._db.find_by_id("departments", department_id)

    @require_auth("departments", "read")
    def list_departments(self, token: str) -> list[dict]:
        return self._db.find("departments")

    @require_auth("departments", "read")
    def get_department_members(self, token: str, department_id: str) -> list[dict]:
        users = self._db.find("users", {"department_id": department_id})
        return [{"id": u["id"], "full_name": u.get("full_name", ""),
                 "role": u.get("role", ""), "email": u.get("email", "")} for u in users]


