class APIResponse:
    """Standardized API response format."""

    @staticmethod
    def success(data: Any = None, message: str = "Success", status_code: int = 200) -> dict:
        return {
            "status": "success",
            "status_code": status_code,
            "message": message,
            "data": data,
            "timestamp": datetime.utcnow().isoformat(),
        }

    @staticmethod
    def error(message: str, status_code: int = 400, errors: list = None) -> dict:
        return {
            "status": "error",
            "status_code": status_code,
            "message": message,
            "errors": errors or [],
            "timestamp": datetime.utcnow().isoformat(),
        }

    @staticmethod
    def paginated(data: dict, message: str = "Success") -> dict:
        return {
            "status": "success",
            "status_code": 200,
            "message": message,
            "data": data.get("data", []),
            "pagination": {
                "total": data.get("total", 0),
                "page": data.get("page", 1),
                "page_size": data.get("page_size", 20),
                "total_pages": data.get("total_pages", 1),
            },
            "timestamp": datetime.utcnow().isoformat(),
        }


class APIRouter:
    """Routes API requests to appropriate service handlers."""

    def __init__(self, app: "TeamSyncPro"):
        self.app = app
        self._routes: dict[str, dict[str, callable]] = {}
        self._register_routes()

    def _register_routes(self):
        self._routes = {
            # Auth endpoints
            "POST /api/auth/register": self._handle_register,
            "POST /api/auth/login": self._handle_login,
            "POST /api/auth/logout": self._handle_logout,
            "GET /api/auth/me": self._handle_get_current_user,
            # Project endpoints
            "POST /api/projects": self._handle_create_project,
            "GET /api/projects": self._handle_list_projects,
            "GET /api/projects/{id}": self._handle_get_project,
            "PUT /api/projects/{id}": self._handle_update_project,
            "GET /api/projects/{id}/stats": self._handle_project_stats,
            "POST /api/projects/{id}/milestones": self._handle_add_milestone,
            # Task endpoints
            "POST /api/tasks": self._handle_create_task,
            "GET /api/tasks": self._handle_list_tasks,
            "GET /api/tasks/{id}": self._handle_get_task,
            "PUT /api/tasks/{id}/status": self._handle_update_task_status,
            "PUT /api/tasks/{id}/assign": self._handle_assign_task,
            "POST /api/tasks/{id}/comments": self._handle_add_comment,
            "POST /api/tasks/{id}/time": self._handle_log_time,
            # Resource endpoints
            "POST /api/resources": self._handle_create_resource,
            "GET /api/resources": self._handle_list_resources,
            "POST /api/resources/{id}/allocate": self._handle_allocate_resource,
            "GET /api/resources/{id}/utilization": self._handle_resource_utilization,
            # Communication endpoints
            "POST /api/channels": self._handle_create_channel,
            "POST /api/channels/{id}/messages": self._handle_send_message,
            "GET /api/channels/{id}/messages": self._handle_get_messages,
            "POST /api/channels/{id}/join": self._handle_join_channel,
            "POST /api/messages/direct": self._handle_direct_message,
            # Report endpoints
            "GET /api/reports/project/{id}": self._handle_project_report,
            "GET /api/reports/resources": self._handle_resource_report,
            "GET /api/reports/performance": self._handle_performance_report,
            "GET /api/reports/department/{id}": self._handle_department_report,
            # Integration endpoints
            "POST /api/integrations": self._handle_register_integration,
            "GET /api/integrations": self._handle_list_integrations,
            "POST /api/integrations/{id}/connect": self._handle_connect_integration,
            "POST /api/integrations/{id}/sync": self._handle_sync_integration,
            # Department endpoints
            "POST /api/departments": self._handle_create_department,
            "GET /api/departments": self._handle_list_departments,
            "GET /api/departments/{id}/members": self._handle_dept_members,
            # Notification endpoints
            "GET /api/notifications": self._handle_get_notifications,
            "PUT /api/notifications/{id}/read": self._handle_mark_notification_read,
            # System endpoints
            "GET /api/system/health": self._handle_health_check,
            "POST /api/system/backup": self._handle_create_backup,
        }

    def handle_request(self, method: str, path: str, body: dict = None,
                       headers: dict = None, query_params: dict = None) -> dict:
        body = body or {}
        headers = headers or {}
        query_params = query_params or {}
        route_key = f"{method.upper()} {path}"
        handler = self._routes.get(route_key)
        if not handler:
            handler = self._find_parameterized_route(method, path)
        if not handler:
            return APIResponse.error("Not found", 404)
        try:
            token = headers.get("Authorization", "").replace("Bearer ", "")
            return handler(token=token, body=body, query_params=query_params, path=path)
        except AuthenticationError as e:
            return APIResponse.error(str(e), 401)
        except AuthorizationError as e:
            return APIResponse.error(str(e), 403)
        except ValueError as e:
            return APIResponse.error(str(e), 400)
        except Exception as e:
            return APIResponse.error(f"Internal server error: {str(e)}", 500)

    def _find_parameterized_route(self, method: str, path: str):
        for route_key, handler in self._routes.items():
            route_method, route_path = route_key.split(" ", 1)
            if route_method != method.upper():
                continue
            if self._path_matches(route_path, path):
                return handler
        return None

    def _path_matches(self, template: str, actual: str) -> bool:
        template_parts = template.split("/")
        actual_parts = actual.split("/")
        if len(template_parts) != len(actual_parts):
            return False
        for t, a in zip(template_parts, actual_parts):
            if t.startswith("{") and t.endswith("}"):
                continue
            if t != a:
                return False
        return True

    def _extract_path_param(self, path: str, position: int = 3) -> str:
        parts = path.split("/")
        if len(parts) > position:
            return parts[position]
        return ""

