class FrontendRenderer:
    """Generates frontend interface components and pages."""

    def __init__(self, app: "TeamSyncPro"):
        self.app = app

    def render_dashboard(self, token: str) -> dict:
        """Render main dashboard view for the current user."""
        try:
            user = self.app.auth_service.get_current_user(token)
            session = self.app.auth_service.validate_session(token)
        except AuthenticationError:
            return self._render_login_page()

        role = UserRole(user.get("role", "viewer"))
        widgets = self._get_role_widgets(role, session["user_id"])
        return {
            "page": "dashboard",
            "user": user,
            "role": role.value,
            "widgets": widgets,
            "navigation": self._get_navigation(role),
            "notifications_count": self._get_unread_count(session["user_id"]),
        }

    def render_project_board(self, token: str, project_id: str) -> dict:
        """Render Kanban-style project board."""
        project = self.app.project_service.get_project(token, project_id)
        if not project:
            return {"page": "error", "message": "Project not found"}
        tasks = self.app.task_service.list_tasks(token, project_id=project_id, page_size=100)
        columns = {
            "backlog": [], "todo": [], "in_progress": [],
            "in_review": [], "done": [], "blocked": [],
        }
        for task in tasks.get("data", []):
            status = task.get("status", "todo")
            if status in columns:
                columns[status].append(task)
        return {
            "page": "project_board",
            "project": project,
            "columns": columns,
            "team_members": self._resolve_team_members(project.get("team_members", [])),
        }

    def render_task_detail(self, token: str, task_id: str) -> dict:
        """Render task detail view with comments and history."""
        task = self.app.task_service.get_task(token, task_id)
        if not task:
            return {"page": "error", "message": "Task not found"}
        return {
            "page": "task_detail",
            "task": task,
            "comments": task.get("comments", []),
            "history": task.get("history", []),
            "assignee": self._resolve_user(task.get("assignee_id", "")),
            "reporter": self._resolve_user(task.get("reporter_id", "")),
        }

    def render_team_view(self, token: str, department_id: str = "") -> dict:
        """Render team/resource view."""
        session = self.app.auth_service.validate_session(token)
        filters = {}
        if department_id:
            filters["department_id"] = department_id
        resources = self.app.resource_service.list_resources(token, department_id=department_id)
        return {
            "page": "team_view",
            "resources": resources.get("data", []),
            "department_id": department_id,
        }

    def render_reports_page(self, token: str) -> dict:
        """Render reports overview page."""
        return {
            "page": "reports",
            "available_reports": [
                {"type": "project_progress", "name": "Project Progress Report",
                 "description": "Track milestones, task completion, and budget"},
                {"type": "resource_utilization", "name": "Resource Utilization Report",
                 "description": "Monitor resource allocation and availability"},
                {"type": "performance_metrics", "name": "Performance Metrics Report",
                 "description": "Team velocity, cycle time, and productivity"},
                {"type": "department_summary", "name": "Department Summary Report",
                 "description": "Cross-project department overview"},
            ],
        }

    def render_communication_hub(self, token: str) -> dict:
        """Render communication/messaging interface."""
        session = self.app.auth_service.validate_session(token)
        channels = self.app.db.find("channels")
        user_channels = [ch for ch in channels if session["user_id"] in ch.get("members", [])]
        return {
            "page": "communication",
            "channels": user_channels,
            "online_users": self.app.communication_service.get_online_users(),
        }

    def _render_login_page(self) -> dict:
        return {"page": "login", "fields": ["username", "password"]}

    def _get_role_widgets(self, role: UserRole, user_id: str) -> list[dict]:
        widgets = [
            {"type": "my_tasks", "title": "My Tasks",
             "data": self.app.db.find("tasks", {"assignee_id": user_id})[:5]},
            {"type": "recent_activity", "title": "Recent Activity",
             "data": self.app.db.find("audit_log")[-10:]},
        ]
        if role in (UserRole.ADMIN, UserRole.MANAGER):
            projects = self.app.db.find("projects", {"status": ProjectStatus.ACTIVE.value})
            widgets.append({"type": "project_overview", "title": "Active Projects",
                           "data": projects[:10]})
            widgets.append({"type": "team_workload", "title": "Team Workload",
                           "data": self._calculate_workload()})
        return widgets

    def _get_navigation(self, role: UserRole) -> list[dict]:
        nav = [
            {"label": "Dashboard", "path": "/dashboard", "icon": "home"},
            {"label": "Projects", "path": "/projects", "icon": "folder"},
            {"label": "Tasks", "path": "/tasks", "icon": "check-square"},
            {"label": "Messages", "path": "/messages", "icon": "message-circle"},
        ]
        if role in (UserRole.ADMIN, UserRole.MANAGER, UserRole.TEAM_LEAD):
            nav.append({"label": "Reports", "path": "/reports", "icon": "bar-chart"})
            nav.append({"label": "Resources", "path": "/resources", "icon": "users"})
        if role == UserRole.ADMIN:
            nav.append({"label": "Settings", "path": "/settings", "icon": "settings"})
            nav.append({"label": "Integrations", "path": "/integrations", "icon": "plug"})
        return nav

    def _get_unread_count(self, user_id: str) -> int:
        return self.app.db.count("notifications", {"user_id": user_id, "is_read": False})

    def _resolve_user(self, user_id: str) -> dict:
        if not user_id:
            return {}
        user = self.app.db.find_by_id("users", user_id)
        return {"id": user_id, "name": user.get("full_name", ""), "role": user.get("role", "")} if user else {}

    def _resolve_team_members(self, member_ids: list[str]) -> list[dict]:
        return [self._resolve_user(uid) for uid in member_ids]

    def _calculate_workload(self) -> list[dict]:
        users = self.app.db.find("users", {"is_active": True})
        workload = []
        for user in users[:20]:
            task_count = self.app.db.count("tasks", {
                "assignee_id": user["id"], "status": TaskStatus.IN_PROGRESS.value,
            })
            workload.append({"user_id": user["id"], "name": user.get("full_name", ""),
                           "active_tasks": task_count})
        return workload


