class TeamSyncPro:
    """
    TeamSyncPro: Main application orchestrator.

    Integrates all subsystems — database, authentication, task management,
    project management, resource allocation, communication, integrations,
    reporting, notifications, and frontend rendering.
    """

    def __init__(self):
        self._start_time = datetime.utcnow()
        self.db = Database()
        self.auth_service = AuthService(self.db)
        self.task_service = TaskManagementService(self.db, self.auth_service)
        self.project_service = ProjectManagementService(self.db, self.auth_service)
        self.resource_service = ResourceAllocationService(self.db, self.auth_service)
        self.communication_service = CommunicationService(self.db, self.auth_service)
        self.integration_service = IntegrationService(self.db, self.auth_service)
        self.reporting_service = ReportingService(self.db, self.auth_service)
        self.notification_service = NotificationService(self.db)
        self.department_service = DepartmentService(self.db, self.auth_service)
        self.frontend = FrontendRenderer(self)
        self.api = APIRouter(self)
        self._setup_indexes()
        self._setup_notification_handlers()

    def _setup_indexes(self):
        self.db.create_index("tasks", "project_id")
        self.db.create_index("tasks", "assignee_id")
        self.db.create_index("tasks", "status")
        self.db.create_index("messages", "channel_id")
        self.db.create_index("notifications", "user_id")
        self.db.create_index("resources", "department_id")

    def _setup_notification_handlers(self):
        self.notification_service.register_handler("task_assigned", self._on_task_assigned)
        self.notification_service.register_handler("deadline_approaching", self._on_deadline)

    def _on_task_assigned(self, notification: dict):
        pass

    def _on_deadline(self, notification: dict):
        pass

    def request(self, method: str, path: str, body: dict = None,
                headers: dict = None, query_params: dict = None) -> dict:
        """Main entry point for processing API requests."""
        return self.api.handle_request(method, path, body, headers, query_params)

    def get_system_info(self) -> dict:
        return {
            "name": "TeamSyncPro",
            "version": "1.0.0",
            "description": "Comprehensive Project Management & Collaboration Platform",
            "started_at": self._start_time.isoformat(),
            "features": [
                "Task Management with workflow automation",
                "Project Management with milestones and budgets",
                "Resource Allocation and utilization tracking",
                "Real-time Communication (channels, DMs)",
                "Role-Based Access Control (5 roles)",
                "Third-party Integrations (Calendar, Email, CRM)",
                "Comprehensive Reporting and Analytics",
                "Department Management",
                "Notification System",
                "Data Backup and Recovery",
            ],
            "api_endpoints": len(self.api._routes),
        }


